Code.Terraform:
```hcl
# 将 SQS 策略限制为特定主体（非公开）
resource "aws_sqs_queue_policy" "<example_resource_name>" {
  queue_url = "<example_queue_url>"
  policy    = jsonencode({
    Version   = "2012-10-17"
    Statement = [{
      Effect    = "Allow"
      Principal = { AWS = "<example_account_id>" } # 关键：限制为特定主体（移除公共的“*”）
      Action    = "sqs:*"
      Resource  = "<example_queue_arn>"
    }]
  })
}
```
